SELECT ?year (COUNT(?race) AS ?wins)
WHERE {
  ?season wdt:P31 wd:Q758 ;
          wdt:P585 ?seasonDate ;
          wdt:P1589 ?race .
  BIND(YEAR(?seasonDate) AS ?year)
  FILTER (?year IN (2008, 2015, 2017, 2018, 2019))
  ?race wdt:P296 wd:Q9673.
}
GROUP BY ?year
ORDER BY DESC(?wins)

